3	public enum UsageHistoryTimeWindow: String, CaseIterable, Identifiable, Sendable {
4	    case sixHours
5	    case twentyFourHours
6	    case sevenDays
7	    case thirtyDays
8	    case all
9	
10	    public var id: String { rawValue }
11	
12	    public var label: String {
13	        switch self {
14	        case .sixHours: "6h"
15	        case .twentyFourHours: "24h"
16	        case .sevenDays: "7d"
17	        case .thirtyDays: "30d"
18	        case .all: "All"
19	        }
20	    }
21	
22	    public func startDate(relativeTo now: Date) -> Date? {
23	        guard let timeInterval else {
24	            return nil
25	        }
26	        return now.addingTimeInterval(-timeInterval)
27	    }
28	
29	    public var timeInterval: TimeInterval? {
30	        switch self {
31	        case .sixHours:
32	            6 * 60 * 60
33	        case .twentyFourHours:
34	            24 * 60 * 60
35	        case .sevenDays:
36	            7 * 24 * 60 * 60
37	        case .thirtyDays:
38	            30 * 24 * 60 * 60
39	        case .all:
40	            nil
41	        }
42	    }
43	}
44	
45	public struct UsageHistoryPoint: Equatable, Identifiable, Sendable {
46	    public let timestamp: Date
47	    public let vendor: Vendor
48	    public let account: AccountEmail
49	    public let metricName: String
50	    public let metricKind: MetricKind
51	    public let value: Double?
52	    public let unit: String
53	
54	    public init(
55	        timestamp: Date,
56	        vendor: Vendor,
57	        account: AccountEmail,
58	        metricName: String,
59	        metricKind: MetricKind,
60	        value: Double?,
61	        unit: String
62	    ) {
63	        self.timestamp = timestamp
64	        self.vendor = vendor
65	        self.account = account
66	        self.metricName = metricName
67	        self.metricKind = metricKind
68	        self.value = value
69	        self.unit = unit
70	    }
71	
72	    public var id: String {
73	        "\(seriesID)|\(timestamp.timeIntervalSince1970)"
74	    }
75	
76	    public var seriesID: String {
77	        "\(vendor.rawValue)|\(account.rawValue)|\(metricName)|\(metricKind.rawValueForDisplay)|\(unit)"
78	    }
79	
80	    public var seriesLabel: String {
81	        "\(vendor.rawValue) / \(account.rawValue) / \(metricName)"
82	    }
83	}
84	
85	public struct UsageHistorySeriesSummary: Equatable, Identifiable, Sendable {
86	    public let id: String
87	    public let label: String
88	    public let metricName: String
89	    public let latestValue: Double
90	    public let unit: String
91	    public let pointCount: Int
92	
93	    public init(id: String, label: String, metricName: String, latestValue: Double, unit: String, pointCount: Int) {
94	        self.id = id
95	        self.label = label
96	        self.metricName = metricName
97	        self.latestValue = latestValue
98	        self.unit = unit
99	        self.pointCount = pointCount
100	    }
101	}
102	
103	public struct UsageHistorySnapshot: Equatable, Sendable {
104	    public static let empty = UsageHistorySnapshot(
105	        points: [],
106	        skippedLineCount: 0,
107	        hasDataBeforeWindow: false,
108	        hasDataAfterWindow: false
109	    )
110	
111	    public let points: [UsageHistoryPoint]
112	    public let skippedLineCount: Int
113	    public let hasDataBeforeWindow: Bool
114	    public let hasDataAfterWindow: Bool
115	
116	    public init(
117	        points: [UsageHistoryPoint],
118	        skippedLineCount: Int,
119	        hasDataBeforeWindow: Bool = false,
120	        hasDataAfterWindow: Bool = false
121	    ) {
122	        self.points = points
123	        self.skippedLineCount = skippedLineCount
124	        self.hasDataBeforeWindow = hasDataBeforeWindow
125	        self.hasDataAfterWindow = hasDataAfterWindow
126	    }
127	
128	    public var seriesSummaries: [UsageHistorySeriesSummary] {
129	        let grouped = Dictionary(grouping: points, by: \.seriesID)
130	        return grouped.compactMap { seriesID, points in
131	            guard let latest = points
132	                .filter({ $0.value != nil })
133	                .max(by: { $0.timestamp < $1.timestamp }),
134	                let latestValue = latest.value else { return nil }
135	            return UsageHistorySeriesSummary(
136	                id: seriesID,
137	                label: latest.seriesLabel,
138	                metricName: latest.metricName,
139	                latestValue: latestValue,
140	                unit: latest.unit,
141	                pointCount: points.filter { $0.value != nil }.count
142	            )
143	        }
144	        .sorted { $0.label.localizedStandardCompare($1.label) == .orderedAscending }
145	    }
146	}
147	
148	public actor UsageHistoryReader {
149	    public nonisolated let rootPath: String
150	    private let fileManager: FileManager
151	    private let logger: FileLogger
152	    private var fileCache: [String: CachedHistoryFile] = [:]
153	
154	    public init(
155	        rootPath: String? = nil,
156	        fileManager: FileManager = .default,
157	        logger: FileLogger = Loggers.app
158	    ) {
159	        let home = FileManager.default.homeDirectoryForCurrentUser.path
160	        self.rootPath = rootPath ?? "\(home)/.cache/ai-usages-tracker/usage-history"
161	        self.fileManager = fileManager
162	        self.logger = logger
163	    }
164	
165	    public func load(window: UsageHistoryTimeWindow, now: Date = Date()) async -> UsageHistorySnapshot {
166	        let startDate = window.startDate(relativeTo: now)
167	        var points: [UsageHistoryPoint] = []
168	        var skippedLineCount = 0
169	        var hasDataBeforeWindow = false
170	        var hasDataAfterWindow = false
171	
172	        let urls = jsonlFileURLs()
173	        pruneCache(keeping: urls)
174	
175	        for url in urls {
176	            guard let decoded = decodedFile(at: url) else { continue }
177	            skippedLineCount += decoded.skippedLineCount
178	
179	            for timestamp in decoded.timestamps {
180	                if let startDate, timestamp < startDate {
181	                    hasDataBeforeWindow = true
182	                } else if timestamp > now {
183	                    hasDataAfterWindow = true
184	                }
185	            }
186	
187	            for point in decoded.points {
188	                if let startDate, point.timestamp < startDate {
189	                    continue
190	                }
191	                if point.timestamp > now {
192	                    continue
193	                }
194	                points.append(point)
195	            }
196	        }
197	
198	        points.sort {
199	            if $0.timestamp == $1.timestamp {
200	                return $0.seriesLabel.localizedStandardCompare($1.seriesLabel) == .orderedAscending
201	            }
202	            return $0.timestamp < $1.timestamp
203	        }
204	        return UsageHistorySnapshot(
205	            points: points,
206	            skippedLineCount: skippedLineCount,
207	            hasDataBeforeWindow: window == .all ? false : hasDataBeforeWindow,
208	            hasDataAfterWindow: window == .all ? false : hasDataAfterWindow
209	        )
210	    }
211	
212	    private func decodedFile(at url: URL) -> DecodedHistoryFile? {
213	        let signature = fileSignature(for: url)
214	        if let signature,
215	           let cached = fileCache[url.path],
216	           cached.signature == signature {
217	            return cached.decoded
218	        }
219	
220	        let data: Data
221	        do {
222	            data = try Data(contentsOf: url)
223	        } catch {
224	            logger.log(.warning, "UsageHistoryReader: cannot read \(url.path): \(error)")
225	            return nil
226	        }
227	
228	        let decoder = JSONDecoder()
229	        var decodedPoints: [UsageHistoryPoint] = []
230	        var timestamps: [Date] = []
231	        var skippedLineCount = 0
232	        let lines = data.split(separator: Self.newlineByte, omittingEmptySubsequences: true)
233	
234	        for line in lines {
235	            do {
236	                let tick = try decoder.decode(TickSnapshot.self, from: Data(line))
237	                guard let timestamp = tick.timestamp.date else {
238	                    continue
239	                }
240	                timestamps.append(timestamp)
241	                decodedPoints.append(contentsOf: Self.points(from: tick, timestamp: timestamp))
242	            } catch {
243	                skippedLineCount += 1
244	            }
245	        }
246	
247	        let decoded = DecodedHistoryFile(
248	            points: decodedPoints,
249	            timestamps: timestamps,
250	            skippedLineCount: skippedLineCount
251	        )
252	        if let signature {
253	            fileCache[url.path] = CachedHistoryFile(signature: signature, decoded: decoded)
254	        }
255	        return decoded
256	    }
257	
258	    private func fileSignature(for url: URL) -> HistoryFileSignature? {
259	        guard let values = try? url.resourceValues(forKeys: [.contentModificationDateKey, .fileSizeKey]) else {
260	            return nil
261	        }
262	        return HistoryFileSignature(
263	            contentModificationDate: values.contentModificationDate,
264	            fileSize: values.fileSize
265	        )
266	    }
267	
268	    private func pruneCache(keeping urls: [URL]) {
269	        let livePaths = Set(urls.map(\.path))
270	        fileCache = fileCache.filter { livePaths.contains($0.key) }
271	    }
272	
273	    private func jsonlFileURLs() -> [URL] {
274	        let rootURL = URL(fileURLWithPath: rootPath, isDirectory: true)
275	        guard let enumerator = fileManager.enumerator(
276	            at: rootURL,
277	            includingPropertiesForKeys: [.isRegularFileKey],
278	            options: [.skipsHiddenFiles]
279	        ) else {
280	            return []
281	        }
282	
283	        var urls: [URL] = []
284	        for case let url as URL in enumerator where url.pathExtension == "jsonl" {
285	            let values = try? url.resourceValues(forKeys: [.isRegularFileKey])
286	            if values?.isRegularFile != false {
287	                urls.append(url)
288	            }
289	        }
290	        return urls.sorted { $0.path.localizedStandardCompare($1.path) == .orderedAscending }
291	    }
292	
293	    private static func points(from tick: TickSnapshot, timestamp: Date) -> [UsageHistoryPoint] {
294	        tick.accounts.flatMap { account in
295	            account.metrics.compactMap { metric in
296	                point(from: metric, account: account, timestamp: timestamp)
297	            }
298	        }
299	    }
300	
301	    private static func point(
302	        from metric: MetricSnapshot,
303	        account: AccountSnapshot,
304	        timestamp: Date
305	    ) -> UsageHistoryPoint? {
306	        switch metric.kind {
307	        case .timeWindow:
308	            return UsageHistoryPoint(
309	                timestamp: timestamp,
310	                vendor: account.vendor,
