import Foundation

public enum UsageHistoryTimeWindow: String, CaseIterable, Identifiable, Sendable {
    case sixHours
    case twentyFourHours
    case sevenDays
    case thirtyDays
    case all

    public var id: String { rawValue }

    public var label: String {
        switch self {
        case .sixHours: "6h"
        case .twentyFourHours: "24h"
        case .sevenDays: "7d"
        case .thirtyDays: "30d"
        case .all: "All"
        }
    }

    public func startDate(relativeTo now: Date) -> Date? {
        guard let timeInterval else {
            return nil
        }
        return now.addingTimeInterval(-timeInterval)
    }

    public var timeInterval: TimeInterval? {
        switch self {
        case .sixHours:
            6 * 60 * 60
        case .twentyFourHours:
            24 * 60 * 60
        case .sevenDays:
            7 * 24 * 60 * 60
        case .thirtyDays:
            30 * 24 * 60 * 60
        case .all:
            nil
        }
    }
}

public struct UsageHistoryPoint: Equatable, Identifiable, Sendable {
    public let timestamp: Date
    public let vendor: Vendor
    public let account: AccountEmail
    public let metricName: String
    public let metricKind: MetricKind
    public let value: Double?
    public let unit: String

    public init(
        timestamp: Date,
        vendor: Vendor,
        account: AccountEmail,
        metricName: String,
        metricKind: MetricKind,
        value: Double?,
        unit: String
    ) {
        self.timestamp = timestamp
        self.vendor = vendor
        self.account = account
        self.metricName = metricName
        self.metricKind = metricKind
        self.value = value
        self.unit = unit
    }

    public var id: String {
        "\(seriesID)|\(timestamp.timeIntervalSince1970)"
    }

    public var seriesID: String {
        "\(vendor.rawValue)|\(account.rawValue)|\(metricName)|\(metricKind.rawValueForDisplay)|\(unit)"
    }

    public var seriesLabel: String {
        "\(vendor.rawValue) / \(account.rawValue) / \(metricName)"
    }
}

public struct UsageHistorySeriesSummary: Equatable, Identifiable, Sendable {
    public let id: String
    public let label: String
    public let metricName: String
    public let latestValue: Double
    public let unit: String
    public let pointCount: Int

    public init(id: String, label: String, metricName: String, latestValue: Double, unit: String, pointCount: Int) {
        self.id = id
        self.label = label
        self.metricName = metricName
        self.latestValue = latestValue
        self.unit = unit
        self.pointCount = pointCount
    }
}

public struct UsageHistorySnapshot: Equatable, Sendable {
    public static let empty = UsageHistorySnapshot(
        points: [],
        skippedLineCount: 0,
        hasDataBeforeWindow: false,
        hasDataAfterWindow: false
    )

    public let points: [UsageHistoryPoint]
    public let skippedLineCount: Int
    public let hasDataBeforeWindow: Bool
    public let hasDataAfterWindow: Bool

    public init(
        points: [UsageHistoryPoint],
        skippedLineCount: Int,
        hasDataBeforeWindow: Bool = false,
        hasDataAfterWindow: Bool = false
    ) {
        self.points = points
        self.skippedLineCount = skippedLineCount
        self.hasDataBeforeWindow = hasDataBeforeWindow
        self.hasDataAfterWindow = hasDataAfterWindow
    }

    public var seriesSummaries: [UsageHistorySeriesSummary] {
        let grouped = Dictionary(grouping: points, by: \.seriesID)
        return grouped.compactMap { seriesID, points in
            guard let latest = points
                .filter({ $0.value != nil })
                .max(by: { $0.timestamp < $1.timestamp }),
                let latestValue = latest.value else { return nil }
            return UsageHistorySeriesSummary(
                id: seriesID,
                label: latest.seriesLabel,
                metricName: latest.metricName,
                latestValue: latestValue,
                unit: latest.unit,
                pointCount: points.filter { $0.value != nil }.count
            )
        }
        .sorted { $0.label.localizedStandardCompare($1.label) == .orderedAscending }
    }
}

public actor UsageHistoryReader {
    public nonisolated let rootPath: String
    private let fileManager: FileManager
    private let logger: FileLogger
    private var fileCache: [String: CachedHistoryFile] = [:]

    public init(
        rootPath: String? = nil,
        fileManager: FileManager = .default,
        logger: FileLogger = Loggers.app
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.rootPath = rootPath ?? "\(home)/.cache/ai-usages-tracker/usage-history"
        self.fileManager = fileManager
        self.logger = logger
    }

    public func load(window: UsageHistoryTimeWindow, now: Date = Date()) async -> UsageHistorySnapshot {
        let startDate = window.startDate(relativeTo: now)
        var points: [UsageHistoryPoint] = []
        var skippedLineCount = 0
        var hasDataBeforeWindow = false
        var hasDataAfterWindow = false

        let urls = jsonlFileURLs()
        pruneCache(keeping: urls)

        for url in urls {
            guard let decoded = decodedFile(at: url) else { continue }
            skippedLineCount += decoded.skippedLineCount

            for timestamp in decoded.timestamps {
                if let startDate, timestamp < startDate {
                    hasDataBeforeWindow = true
                } else if timestamp > now {
                    hasDataAfterWindow = true
                }
            }

            for point in decoded.points {
                if let startDate, point.timestamp < startDate {
                    continue
                }
                if point.timestamp > now {
                    continue
                }
                points.append(point)
            }
        }

        points.sort {
            if $0.timestamp == $1.timestamp {
                return $0.seriesLabel.localizedStandardCompare($1.seriesLabel) == .orderedAscending
            }
            return $0.timestamp < $1.timestamp
        }
        return UsageHistorySnapshot(
            points: points,
            skippedLineCount: skippedLineCount,
            hasDataBeforeWindow: window == .all ? false : hasDataBeforeWindow,
            hasDataAfterWindow: window == .all ? false : hasDataAfterWindow
        )
    }

    private func decodedFile(at url: URL) -> DecodedHistoryFile? {
        let signature = fileSignature(for: url)
        if let signature,
           let cached = fileCache[url.path],
           cached.signature == signature {
            return cached.decoded
        }

        let data: Data
        do {
            data = try Data(contentsOf: url)
        } catch {
            logger.log(.warning, "UsageHistoryReader: cannot read \(url.path): \(error)")
            return nil
        }

        let decoder = JSONDecoder()
        var decodedPoints: [UsageHistoryPoint] = []
        var timestamps: [Date] = []
        var skippedLineCount = 0
        let lines = data.split(separator: Self.newlineByte, omittingEmptySubsequences: true)

        for line in lines {
            do {
                let tick = try decoder.decode(TickSnapshot.self, from: Data(line))
                guard let timestamp = tick.timestamp.date else {
                    continue
                }
                timestamps.append(timestamp)
                decodedPoints.append(contentsOf: Self.points(from: tick, timestamp: timestamp))
            } catch {
                skippedLineCount += 1
            }
        }

        let decoded = DecodedHistoryFile(
            points: decodedPoints,
            timestamps: timestamps,
            skippedLineCount: skippedLineCount
        )
        if let signature {
            fileCache[url.path] = CachedHistoryFile(signature: signature, decoded: decoded)
        }
        return decoded
    }

    private func fileSignature(for url: URL) -> HistoryFileSignature? {
        guard let values = try? url.resourceValues(forKeys: [.contentModificationDateKey, .fileSizeKey]) else {
            return nil
        }
        return HistoryFileSignature(
            contentModificationDate: values.contentModificationDate,
            fileSize: values.fileSize
        )
    }

    private func pruneCache(keeping urls: [URL]) {
        let livePaths = Set(urls.map(\.path))
        fileCache = fileCache.filter { livePaths.contains($0.key) }
    }

    private func jsonlFileURLs() -> [URL] {
        let rootURL = URL(fileURLWithPath: rootPath, isDirectory: true)
        guard let enumerator = fileManager.enumerator(
            at: rootURL,
            includingPropertiesForKeys: [.isRegularFileKey],
            options: [.skipsHiddenFiles]
        ) else {
            return []
        }

        var urls: [URL] = []
        for case let url as URL in enumerator where url.pathExtension == "jsonl" {
            let values = try? url.resourceValues(forKeys: [.isRegularFileKey])
            if values?.isRegularFile != false {
                urls.append(url)
            }
        }
        return urls.sorted { $0.path.localizedStandardCompare($1.path) == .orderedAscending }
    }

    private static func points(from tick: TickSnapshot, timestamp: Date) -> [UsageHistoryPoint] {
        tick.accounts.flatMap { account in
            account.metrics.compactMap { metric in
                point(from: metric, account: account, timestamp: timestamp)
            }
        }
    }

    private static func point(
        from metric: MetricSnapshot,
        account: AccountSnapshot,
        timestamp: Date
    ) -> UsageHistoryPoint? {
        switch metric.kind {
        case .timeWindow:
            return UsageHistoryPoint(
                timestamp: timestamp,
                vendor: account.vendor,
                account: account.account,
                metricName: metric.name,
                metricKind: metric.kind,
                value: metric.usagePercent.map { Double($0.rawValue) },
                unit: "%"
            )
        case .payAsYouGo:
            return UsageHistoryPoint(
                timestamp: timestamp,
                vendor: account.vendor,
                account: account.account,
                metricName: metric.name,
                metricKind: metric.kind,
                value: metric.currentAmount,
                unit: metric.currency ?? ""
            )
        case .unknown:
            return nil
        }
    }

    private static let newlineByte: UInt8 = 0x0A
}

private struct HistoryFileSignature: Equatable {
    let contentModificationDate: Date?
    let fileSize: Int?
}

private struct DecodedHistoryFile {
    let points: [UsageHistoryPoint]
    let timestamps: [Date]
    let skippedLineCount: Int
}

private struct CachedHistoryFile {
    let signature: HistoryFileSignature
    let decoded: DecodedHistoryFile
}

private extension MetricKind {
    var rawValueForDisplay: String {
        switch self {
        case .timeWindow: "time-window"
        case .payAsYouGo: "pay-as-you-go"
        case .unknown(let rawValue): rawValue
        }
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("UsageHistoryReader")
struct UsageHistoryReaderTests {
    private static func makeTempRoot() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-history-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private static func makeLogger(in dir: String) -> FileLogger {
        FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
    }

    private static func date(_ rawValue: String) -> Date {
        ISO8601DateFormatter().date(from: rawValue)!
    }

    private static func tick(
        timestamp: String,
        account: AccountEmail = "a@b.com",
        metrics: [MetricSnapshot]
    ) throws -> String {
        let snapshot = TickSnapshot(
            timestamp: ISODate(rawValue: timestamp),
            accounts: [AccountSnapshot(vendor: "claude", account: account, metrics: metrics)]
        )
        let data = try SnapshotRecorder.encode(snapshot)
        return String(decoding: data, as: UTF8.self)
    }

    private static func writeLines(_ lines: [String], to path: String) throws {
        let url = URL(fileURLWithPath: path)
        try FileManager.default.createDirectory(
            at: url.deletingLastPathComponent(),
            withIntermediateDirectories: true
        )
        try lines.joined(separator: "\n").appending("\n").write(to: url, atomically: true, encoding: .utf8)
    }

    @Test("loads JSONL snapshots recursively and flattens metric values")
    func loadsSnapshotsRecursively() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 40),
                MetricSnapshot(name: "spend", kind: .payAsYouGo, currentAmount: 1.25, currency: "USD"),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.count == 2)
        #expect(snapshot.points.contains { $0.metricName == "session" && $0.value == 40 && $0.unit == "%" })
        #expect(snapshot.points.contains { $0.metricName == "spend" && $0.value == 1.25 && $0.unit == "USD" })
        #expect(snapshot.skippedLineCount == 0)
    }

    @Test("reloads cached JSONL files when they change")
    func reloadsCachedFileWhenChanged() async throws {
        let root = Self.makeTempRoot()
        let path = "\(root)/2026/04/2026-04-20.jsonl"
        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 40),
            ]),
        ], to: path)

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let first = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 40),
            ]),
            try Self.tick(timestamp: "2026-04-20T10:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: path)
        let second = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(first.points.map(\.value) == [40.0])
        #expect(second.points.map(\.value) == [40.0, 55.0])
    }

    @Test("filters points outside the selected time window")
    func filtersBySelectedWindow() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-19T05:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 10),
            ]),
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.map(\.value) == [55.0])
    }

    @Test("reports whether data exists before and after the selected window")
    func reportsDataOutsideSelectedWindow() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-19T05:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 10),
            ]),
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
            try Self.tick(timestamp: "2026-04-21T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 70),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.map(\.value) == [55.0])
        #expect(snapshot.hasDataBeforeWindow)
        #expect(snapshot.hasDataAfterWindow)
    }

    @Test("all time disables outside-window navigation flags")
    func allTimeDisablesNavigationFlags() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-03-01T05:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 10),
            ]),
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .all, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(!snapshot.hasDataBeforeWindow)
        #expect(!snapshot.hasDataAfterWindow)
    }

    @Test("all time includes older points")
    func allTimeIncludesOlderPoints() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-03-01T05:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 10),
            ]),
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .all, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.map(\.value) == [10.0, 55.0])
    }

    @Test("skips malformed JSONL lines without failing the whole load")
    func skipsMalformedLines() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            "{not-json",
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.count == 1)
        #expect(snapshot.skippedLineCount == 1)
    }

    @Test("keeps null metric values so charts can break the line")
    func keepsNullMetricValues() async throws {
        let root = Self.makeTempRoot()
        try Self.writeLines([
            try Self.tick(timestamp: "2026-04-20T09:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 40),
            ]),
            try Self.tick(timestamp: "2026-04-20T10:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: nil),
            ]),
            try Self.tick(timestamp: "2026-04-20T11:00:00Z", metrics: [
                MetricSnapshot(name: "session", kind: .timeWindow, usagePercent: 55),
            ]),
        ], to: "\(root)/2026/04/2026-04-20.jsonl")

        let reader = UsageHistoryReader(rootPath: root, logger: Self.makeLogger(in: root))
        let snapshot = await reader.load(window: .twentyFourHours, now: Self.date("2026-04-20T12:00:00Z"))

        #expect(snapshot.points.map(\.value) == [40.0, nil, 55.0])
        #expect(snapshot.seriesSummaries.first?.latestValue == 55)
        #expect(snapshot.seriesSummaries.first?.pointCount == 2)
    }
}

