335	        let plottedPoints: [PlottedChartPoint] = visiblePoints.compactMap { item in
336	            guard let value = item.point.value else { return nil }
337	            return PlottedChartPoint(chartPoint: item, value: value)
338	        }
339	
340	        self.title = configuration.title
341	        self.selectedWindow = selectedWindow
342	        self.plottedPoints = plottedPoints
343	        self.summaries = Self.makeSummaries(from: series)
