348	            referenceDate: referenceDate
349	        )
350	        self.seriesStyles = Dictionary(uniqueKeysWithValues: series.enumerated().map { index, series in
351	            let style = series.style ?? ChartSeriesStyle(
352	                color: ChartSeriesColor.allCases[index % ChartSeriesColor.allCases.count],
353	                lineStyle: .solid
354	            )
355	            return (series.id, style)
356	        })
357	        self.pointsBySeries = Dictionary(grouping: visiblePoints, by: \.seriesID)
358	    }
