360	    func nearestHoverPoints(at date: Date) -> [HoverItem] {
361	        summaries.compactMap { summary in
362	            guard let seriesPoints = pointsBySeries[summary.id],
363	                  let nearest = Self.nearestPoint(in: seriesPoints, to: date) else {
364	                return nil
365	            }
366	            return HoverItem(
367	                label: summary.label,
368	                seriesID: summary.id,
369	                value: nearest.point.value,
370	                unit: nearest.point.unit
371	            )
372	        }
373	        .sorted { $0.label.localizedStandardCompare($1.label) == .orderedAscending }
374	    }
