376	    private static func makeVisiblePoints(from series: [ResolvedChartSeries]) -> [ChartPoint] {
377	        series.flatMap { series in
378	            var segmentIndex = 0
379	            return series.points.map { point in
380	                let item = ChartPoint(
381	                    seriesID: series.id,
382	                    segmentID: "\(series.id)|segment|\(segmentIndex)",
383	                    point: point
384	                )
385	                if point.value == nil {
386	                    segmentIndex += 1
387	                }
388	                return item
389	            }
390	        }
391	    }
