393	    private static func makeSummaries(from series: [ResolvedChartSeries]) -> [UsageHistorySeriesSummary] {
394	        series.compactMap { series in
395	            let valuedPoints = series.points.filter { $0.value != nil }
396	            guard let latest = valuedPoints.max(by: { $0.timestamp < $1.timestamp }),
397	                  let latestValue = latest.value else { return nil }
398	            return UsageHistorySeriesSummary(
399	                id: series.id,
400	                label: series.label,
401	                metricName: latest.metricName,
402	                latestValue: latestValue,
403	                unit: latest.unit,
404	                pointCount: valuedPoints.count
405	            )
406	        }
407	    }
