409	    private static func makeYAxisLabel(from plottedPoints: [PlottedChartPoint]) -> String {
410	        let units = Set(plottedPoints.map(\.point.unit).filter { !$0.isEmpty })
411	        if units.count == 1, let unit = units.first {
412	            return unit == "%" ? "Usage (%)" : "Usage (\(unit))"
413	        }
414	        return "Usage"
415	    }
416	
417	    private static func makeXDomain(
418	        from plottedPoints: [PlottedChartPoint],
419	        selectedWindow: UsageHistoryTimeWindow,
420	        referenceDate: Date
421	    ) -> ClosedRange<Date> {
422	        if let startDate = selectedWindow.startDate(relativeTo: referenceDate) {
423	            return startDate...referenceDate
424	        }
425	
426	        let timestamps = plottedPoints.map(\.point.timestamp)
427	        guard let first = timestamps.min(),
428	              let last = timestamps.max() else {
429	            return referenceDate.addingTimeInterval(-60 * 60)...referenceDate
430	        }
431	        if first == last {
432	            return first.addingTimeInterval(-30 * 60)...last.addingTimeInterval(30 * 60)
433	        }
434	        return first...last
435	    }
436	
437	    private static func nearestPoint(in points: [ChartPoint], to date: Date) -> ChartPoint? {
438	        guard !points.isEmpty else { return nil }
439	
440	        var lowerBound = 0
441	        var upperBound = points.count
442	        while lowerBound < upperBound {
443	            let midpoint = (lowerBound + upperBound) / 2
444	            if points[midpoint].point.timestamp < date {
445	                lowerBound = midpoint + 1
446	            } else {
447	                upperBound = midpoint
448	            }
449	        }
450	
451	        if lowerBound == 0 {
452	            return points[0]
453	        }
454	        if lowerBound == points.count {
455	            return points[points.count - 1]
456	        }
457	
458	        let previous = points[lowerBound - 1]
459	        let next = points[lowerBound]
460	        let previousDistance = abs(previous.point.timestamp.timeIntervalSince(date))
461	        let nextDistance = abs(next.point.timestamp.timeIntervalSince(date))
462	        return previousDistance <= nextDistance ? previous : next
463	    }
464	}
