474	    let seriesID: String
475	    let segmentID: String
476	    let point: UsageHistoryPoint
477	
478	    var id: String {
479	        "\(seriesID)|\(point.timestamp.timeIntervalSince1970)|\(point.metricName)"
480	    }
481	}
