483	private struct PlottedChartPoint: Identifiable {
484	    let chartPoint: ChartPoint
485	    let value: Double
486	
487	    var id: String { chartPoint.id }
488	    var seriesID: String { chartPoint.seriesID }
489	    var segmentID: String { chartPoint.segmentID }
490	    var point: UsageHistoryPoint { chartPoint.point }
491	}
