165	    public func load(window: UsageHistoryTimeWindow, now: Date = Date()) async -> UsageHistorySnapshot {
166	        let startDate = window.startDate(relativeTo: now)
167	        var points: [UsageHistoryPoint] = []
168	        var lastPreWindowPoints: [String: UsageHistoryPoint] = [:]
169	        var firstPostWindowPoints: [String: UsageHistoryPoint] = [:]
170	        var skippedLineCount = 0
171	        var hasDataBeforeWindow = false
172	        var hasDataAfterWindow = false
173	
174	        let urls = jsonlFileURLs()
175	        pruneCache(keeping: urls)
176	
177	        for url in urls {
178	            guard let decoded = decodedFile(at: url) else { continue }
179	            skippedLineCount += decoded.skippedLineCount
180	
181	            for timestamp in decoded.timestamps {
182	                if let startDate, timestamp < startDate {
183	                    hasDataBeforeWindow = true
184	                } else if timestamp > now {
185	                    hasDataAfterWindow = true
186	                }
187	            }
188	
189	            for point in decoded.points {
190	                if let startDate, point.timestamp < startDate {
191	                    lastPreWindowPoints[point.seriesID] = point
192	                    continue
193	                }
194	                if point.timestamp > now {
195	                    if firstPostWindowPoints[point.seriesID] == nil {
196	                        firstPostWindowPoints[point.seriesID] = point
197	                    }
198	                    continue
199	                }
200	                points.append(point)
201	            }
202	        }
203	
204	        points.append(contentsOf: lastPreWindowPoints.values)
205	        if window != .all {
206	            points.append(contentsOf: firstPostWindowPoints.values)
